parameters.jsCode:
const raw = $json;

const subject = raw.subject || '';
const snippet = raw.snippet || '';
const textBody = raw.textPlain || raw.textHtml || raw.bodyPlain || raw.bodyHtml || '';
const body = `${snippet}\n${textBody}`;
const from = raw.from || '';
const messageId = raw.id || raw.messageId || '';
const threadId = raw.threadId || '';

function matchOne(patterns, text) {
  for (const p of patterns) {
    const m = text.match(p);
    if (m && m[1]) return m[1].trim();
  }
  return '';
}

function cleanPhone(phone) {
  return phone ? phone.replace(/\s+/g, ' ').trim() : '';
}

const lowerBody = body.toLowerCase();
const lowerSubject = subject.toLowerCase();

let status = '';
if (/submission started/.test(lowerSubject) || /submission started/.test(lowerBody)) status = 'Submission started';
else if (/application incomplete/.test(lowerSubject) || /application incomplete/.test(lowerBody)) status = 'Application incomplete';
else if (/client file closed/.test(lowerSubject) || /client file closed/.test(lowerBody)) status = 'Client file closed';
else if (/funded/.test(lowerSubject) || /funded/.test(lowerBody)) status = 'Funded';
else if (/approved/.test(lowerSubject) || /approved/.test(lowerBody)) status = 'Approved';
else if (/under review/.test(lowerSubject) || /under review/.test(lowerBody) || /in review/.test(lowerBody)) status = 'Under review';
else status = 'Unknown';

let routeDetected = 'Unknown';
if (/giggle/.test(lowerBody) || /giggle/.test(lowerSubject)) routeDetected = 'Giggle Finance';
if (/bankbreezy/.test(lowerBody) || /bankbreezy/.test(lowerSubject)) routeDetected = 'BankBreezy';

const applicantEmail = matchOne([
  /([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,})/i,
  /email\s*[:\-]\s*([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,})/i
], body);

const applicantName = matchOne([
  /name\s*[:\-]\s*([^\n\r]+)/i,
  /applicant\s*[:\-]\s*([^\n\r]+)/i,
  /customer\s*[:\-]\s*([^\n\r]+)/i
], body);

const phone = cleanPhone(matchOne([
  /phone\s*[:\-]\s*([^\n\r]+)/i,
  /mobile\s*[:\-]\s*([^\n\r]+)/i,
 /(\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4})/
], body));

const revenue = matchOne([
  /\$\s?([\d,]+)\s*(?:\/month|per month|monthly)/i,
  /monthly revenue\s*[:\-]\s*\$?\s*([\d,]+)/i,
  /revenue\s*[:\-]\s*\$?\s*([\d,]+)/i
], body).replace(/,/g, '');

let bankType = '';
if (/personal bank/.test(lowerBody) || /personal account/.test(lowerBody)) bankType = 'Personal';
if (/business bank/.test(lowerBody) || /business account/.test(lowerBody)) bankType = 'Business';

const businessName = matchOne([
  /business name\s*[:\-]\s*([^\n\r]+)/i,
  /company\s*[:\-]\s*([^\n\r]+)/i
], body);

const source = from || 'Gmail Applicant Intake';

const candidate = {
  source,
  emailSubject: subject,
  applicantName,
  applicantEmail,
  phone,
  businessName,
  routeDetected,
  revenue,
  bankType,
  status,
  firstReplySent: false,
  messageId,
  threadId,
  notes: `Parsed from Gmail. Sender: ${from}`,
  rawBodyPreview: body.slice(0, 1200)
};

return [candidate];

parameters.responseBody:
={
  "ok": true,
  "message": "Email did not contain a confidently parsed applicant email; skipped.",
  "subject": "{{$json.emailSubject}}",
  "from": "{{$json.source}}"
}
